const routing = {
  'TBB': 'tbb@freiescholle.de',
  'Vermietung': 'vermietung@freiescholle.de',
  'Mitglieder': 'mitglieder@freiescholle.de',
  'Rechnungswesen': 'rechnungswesen@freiescholle.de',
  'HSG': 'hsg@freiescholle.de',
  'Öffentlichkeitsarbeit': 'presse@freiescholle.de'
};

const category = $input.item.json['Kategorie'];
const email = routing[category] || 'info@freiescholle.de';
const isUrgent = $input.item.json['Dringlichkeit'] === 'dringend';
const prefix = isUrgent ? '[DRINGEND] ' : '';

return [{
  json: {
    ...$input.item.json,
    department_email: email,
    department: category,
    subject_prefix: prefix
  }
}];

